<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <meta http-equiv="X-UA-Compatible" content="ie=edge">
    <title>@yield('title', 'jiidaa')</title>
    <style>
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body {
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
            line-height: 1.6;
            color: #272518;
            background-color: #f2f0eb;
        }
        .wrapper {
            background-color: #f2f0eb;
            padding: 40px 16px;
        }
        .email-container {
            max-width: 580px;
            margin: 0 auto;
            background-color: #ffffff;
            border-radius: 12px;
            overflow: hidden;
            box-shadow: 0 4px 24px rgba(39,37,24,0.10);
        }

        /* ── Header ── */
        .email-header {
            background: linear-gradient(135deg, #272518 0%, #523026 100%);
            padding: 36px 40px 32px;
            text-align: center;
        }

        /* ── Body ── */
        .email-body {
            padding: 40px 40px 32px;
        }
        .email-body h2 {
            color: #272518;
            font-size: 22px;
            font-weight: 700;
            margin-bottom: 16px;
        }
        .email-body p {
            color: #555;
            font-size: 15px;
            margin: 12px 0;
            line-height: 1.7;
        }

        /* ── Button ── */
        .button-container {
            text-align: center;
            margin: 32px 0;
        }
        .action-button {
            display: inline-block;
            padding: 15px 44px;
            background: linear-gradient(135deg, #272518 0%, #523026 100%);
            color: #ffffff !important;
            text-decoration: none;
            border-radius: 8px;
            font-weight: 600;
            font-size: 15px;
            letter-spacing: 0.2px;
        }

        /* ── Info box ── */
        .info-box {
            background-color: #faf9f7;
            border-left: 4px solid #86885e;
            padding: 14px 18px;
            margin: 24px 0;
            border-radius: 4px;
        }
        .info-box p {
            margin: 0;
            color: #666;
            font-size: 13px;
            line-height: 1.6;
        }

        /* ── Divider ── */
        .divider {
            border: none;
            border-top: 1px solid #ece9e3;
            margin: 28px 0;
        }

        /* ── Link fallback ── */
        .link-fallback p {
            font-size: 13px;
            color: #888;
            margin-bottom: 8px;
        }
        .link-text {
            word-break: break-all;
            color: #86885e;
            font-size: 12px;
        }

        /* ── Footer ── */
        .email-footer {
            background-color: #272518;
            padding: 24px 40px;
            text-align: center;
        }
        .email-footer p {
            color: rgba(202,207,202,0.7);
            font-size: 12px;
            margin: 4px 0;
            line-height: 1.6;
        }

        @media only screen and (max-width: 600px) {
            .wrapper { padding: 20px 12px; }
            .email-header { padding: 28px 24px; }
            .email-body { padding: 28px 24px; }
            .email-footer { padding: 20px 24px; }
            .action-button { padding: 14px 32px; font-size: 14px; }
        }
    </style>
</head>
